#pragma once
#include "SerialIO.h"
#include "VESC.h"
#include "CRSFRouter.h"

class SerialVESC final : public SerialIO, public CRSFConnector {
public:
    explicit SerialVESC(Stream &out, Stream &in)
        : SerialIO(&out, &in)
    {
        crsfRouter.addConnector(this);
    }
    ~SerialVESC() override;

    void begin(uint8_t idx, int8_t pin = -1, int8_t pin_rx = -1);

    uint32_t sendRCFrame(bool frameAvailable, bool frameMissed, uint32_t *channelData) override;
    void forwardMessage(const crsf_header_t *message) override;

    bool sendImmediateRC() override { return true; }

private:
    void processBytes(uint8_t *bytes, uint16_t size) override;
    bool processPacketPayload(const uint8_t *message, uint8_t payloadLength, uint16_t cachedLength);
    void resetReceiveState();
    bool handleTcpBridge(uint8_t *bytes, uint16_t size);

    enum receive_state_e : uint8_t {
        RECEIVE_WAIT_START,
        RECEIVE_LENGTH,
        RECEIVE_PAYLOAD,
        RECEIVE_CRC_HIGH,
        RECEIVE_CRC_LOW,
        RECEIVE_STOP
    };

    // COMM_GET_VALUES currently consumes 59 payload bytes total:
    // 1 byte packet id + 58 bytes of decoded/skipped fields. Keep a little
    // headroom so minor payload growth does not immediately require resizing.
    static constexpr uint16_t PAYLOAD_CACHE_SIZE = 256;

    bool configed = false; // indicate if begin() has been called
    uint8_t idx;           // either 0 for main Serial, or 1 for Serial1
    int pin;               // physical GPIO number
    int pin_rx;            // physical GPIO number
    vesc_cfg_t cfg[3];     // loaded configuration cached here
    int32_t range[3];      // cached decoded range value

    bool is_main_vesc = false; // the main VESC is the one with the RX pin, it can use telemetry and TCP bridge

    receive_state_e receiveState = RECEIVE_WAIT_START;
    uint8_t payloadLength = 0;
    uint16_t payloadBytesReceived = 0;
    uint16_t payloadBytesCached = 0;
    uint8_t payloadCache[PAYLOAD_CACHE_SIZE] = {};
    uint16_t calculatedCrc = 0;
    uint16_t receivedCrc = 0;
    uint32_t last_byte_time = 0;
    uint32_t last_packet_time = 0;
    uint32_t last_req_time = 0;

    vesc_telem_t telem_data;
};

#include "CRSFRouter.h"

#include "msptypes.h"

elrsLinkStatistics_t linkStats {};

void CRSFRouter::addConnector(CRSFConnector *connector)
{
    connectors.insert(connector);
}

void CRSFRouter::removeConnector(CRSFConnector *connector)
{
    connectors.erase(connector);
}

void CRSFRouter::addEndpoint(CRSFEndpoint *endpoint)
{
    endpoints.insert(endpoint);
}

void CRSFRouter::processMessage(CRSFConnector *connector, const crsf_header_t *message) const
{
    if (message->type == CRSF_FRAMETYPE_HEARTBEAT)
    {
        if (connector)
        {
            // The spec say's the heartbeat payload is a int16_t, so we skip the leading byte; because it's in MSB format
            connector->addDevice((crsf_addr_e)((uint8_t *)message)[sizeof(crsf_header_t) + 1]);
        }
        return;
    }

    const auto extMessage = (crsf_ext_header_t *)message;
    const crsf_frame_type_e packetType = message->type;
    if (connector && packetType >= CRSF_FRAMETYPE_DEVICE_PING)
    {
        connector->addDevice(extMessage->orig_addr);
    }

    for (const auto endpoint : endpoints)
    {
        if (endpoint->handleRaw(message))
        {
            return;
        }

        const crsf_addr_e device_id = endpoint->getDeviceId();
        if (packetType < CRSF_FRAMETYPE_DEVICE_PING || extMessage->dest_addr == device_id || extMessage->dest_addr == CRSF_ADDRESS_BROADCAST)
        {
            endpoint->handleMessage(message);
            if (packetType >= CRSF_FRAMETYPE_DEVICE_PING && extMessage->dest_addr == device_id)
            {
                return;
            }
        }
    }

    deliverMessage(connector, message);
}

void CRSFRouter::deliverMessage(const CRSFConnector *connector, const crsf_header_t *message) const
{
    const crsf_frame_type_e packetType = message->type;
    const auto extMessage = (crsf_ext_header_t *)message;

    // deliver extended header messages to the connector that 'knows' about the destination device address
    if (packetType >= CRSF_FRAMETYPE_DEVICE_PING && extMessage->dest_addr != CRSF_ADDRESS_BROADCAST)
    {
        for (const auto other : connectors)
        {
            if (other != connector && other->forwardsTo(extMessage->dest_addr))
            {
                other->forwardMessage(message);
                return;
            }
        }
    }

    // The destination is not known, or it's a broadcast message so deliver to all other connectors
    for (const auto other : connectors)
    {
        if (other != connector)
        {
            other->forwardMessage(message);
        }
    }
}

void CRSFRouter::deliverMessageTo(const crsf_addr_e destination, const crsf_header_t *message) const
{
    for (const auto other : connectors)
    {
        if (destination == CRSF_ADDRESS_BROADCAST || other->forwardsTo(destination))
        {
            other->forwardMessage(message);
            if (destination != CRSF_ADDRESS_BROADCAST) return;
        }
    }
}

void CRSFRouter::SetHeaderAndCrc(crsf_header_t *frame, const crsf_frame_type_e frameType, const uint8_t frameSize)
{
    frame->sync_byte = CRSF_SYNC_BYTE;
    frame->frame_size = frameSize;
    frame->type = frameType;

    const uint8_t crc = crsf_crc.calc((uint8_t *)frame + CRSF_FRAME_NOT_COUNTED_BYTES, frameSize - 1, 0);
    ((uint8_t*)frame)[frameSize + CRSF_FRAME_NOT_COUNTED_BYTES - 1] = crc;
}

void CRSFRouter::SetExtendedHeaderAndCrc(crsf_ext_header_t *frame, const crsf_frame_type_e frameType, const uint8_t frameSize, const crsf_addr_e destAddr, const crsf_addr_e origAddr)
{
    frame->dest_addr = destAddr;
    frame->orig_addr = origAddr;
    SetHeaderAndCrc((crsf_header_t *)frame, frameType, frameSize);
}

void CRSFRouter::makeLinkStatisticsPacket(uint8_t *buffer)
{
    // Note: size of crsfLinkStatistics_t used, not full elrsLinkStatistics_t
    constexpr uint8_t payloadLen = sizeof(crsfLinkStatistics_t);

    buffer[0] = CRSF_SYNC_BYTE;
    buffer[1] = CRSF_FRAME_SIZE(payloadLen);
    buffer[2] = CRSF_FRAMETYPE_LINK_STATISTICS;
    memcpy(&buffer[3], &linkStats, payloadLen);
    buffer[payloadLen + 3] = crsf_crc.calc(&buffer[2], payloadLen + 1);
}

void CRSFRouter::SetMspV2Request(uint8_t *frame, const uint16_t function, const uint8_t *payload, const uint8_t payloadLength)
{
    auto *packet = frame + sizeof(crsf_ext_header_t);
    packet[0] = 0x50;          // no error, version 2, beginning of the frame, first frame (0)
    packet[1] = 0;             // flags
    packet[2] = function & 0xFF;
    packet[3] = (function >> 8) & 0xFF;
    packet[4] = payloadLength & 0xFF;
    packet[5] = (payloadLength >> 8) & 0xFF;
    memcpy(packet + 6, payload, payloadLength);
    packet[6 + payloadLength] = CalcCRCMsp(packet + 1, payloadLength + 5); // crc = flags + function + length + payload
}

void CRSFRouter::AddMspMessage(const mspPacket_t *packet, const crsf_addr_e destination, const crsf_addr_e origin)
{
    if (packet->payloadSize > ENCAPSULATED_MSP_MAX_PAYLOAD_SIZE)
    {
        return;
    }

    const uint8_t totalBufferLen = packet->payloadSize + ENCAPSULATED_MSP_HEADER_CRC_LEN + CRSF_FRAME_LENGTH_EXT_TYPE_CRC + CRSF_FRAME_NOT_COUNTED_BYTES;
    uint8_t outBuffer[ENCAPSULATED_MSP_MAX_FRAME_LEN + CRSF_FRAME_LENGTH_EXT_TYPE_CRC + CRSF_FRAME_NOT_COUNTED_BYTES];

    // CRSF extended frame header
    outBuffer[0] = CRSF_SYNC_BYTE;                                                                         // address
    outBuffer[1] = packet->payloadSize + ENCAPSULATED_MSP_HEADER_CRC_LEN + CRSF_FRAME_LENGTH_EXT_TYPE_CRC; // length
    outBuffer[2] = CRSF_FRAMETYPE_MSP_WRITE;                                                               // packet type
    outBuffer[3] = destination;                                                                            // destination
    outBuffer[4] = origin;                                                                                 // origin

    // Encapsulated MSP payload
    outBuffer[5] = 0x30;                // header
    outBuffer[6] = packet->payloadSize; // mspPayloadSize
    outBuffer[7] = packet->function;    // packet->cmd

    // Copy packet payload into outBuffer
    for (uint16_t i = 0; i < packet->payloadSize; ++i)
    {
        outBuffer[8 + i] = packet->payload[i];
    }

    // Encapsulated MSP crc
    outBuffer[totalBufferLen - 2] = CalcCRCMsp(&outBuffer[6], packet->payloadSize + 2);

    // CRSF frame crc
    outBuffer[totalBufferLen - 1] = crsf_crc.calc(&outBuffer[2], packet->payloadSize + ENCAPSULATED_MSP_HEADER_CRC_LEN + CRSF_FRAME_LENGTH_EXT_TYPE_CRC - 1);
    deliverMessageTo(destination, (crsf_header_t *)outBuffer);
}

uint8_t CRSFRouter::getConnectorMaxPacketSize(const crsf_addr_e origin) const
{
    for (const auto connector : connectors)
    {
        if (connector->forwardsTo(origin))
        {
            return connector->GetMaxPacketBytes();
        }
    }
    return CRSF_MAX_PACKET_LEN;
}

#ifndef CRSF_ROUTER_H
#define CRSF_ROUTER_H

#include "CRSFConnector.h"
#include "CRSFEndpoint.h"
#include "crc.h"
#include "msp.h"

#include <vector>

class CRSFRouter final
{
public:
    CRSFRouter() = default;
    ~CRSFRouter() = default;

    /**
     * Adds a CRSFConnector instance to the list of connectors managed by this CRSFRouter.
     *
     * Connectors are the ports that communicate with other devices in the network.
     *
     * @param connector Pointer to the CRSFConnector that will be added to the endpoint's managed connectors.
     */
    void addConnector(CRSFConnector *connector);

    /**
     * Removes a CRSFConnector instance from the list of connectors managed by this CRSFRouter.
     *
     * @param connector Pointer to the CRSFConnector that will be removed from the endpoint's managed connectors.
     */
    void removeConnector(CRSFConnector * connector);

    /**
     * Adds a CRSFEndpoint instance to the list of endpoints managed by this CRSFRouter.
     *
     * Endpoints are the targets of messages and are expected to process the messages that are sent to them.
     *
     * @param endpoint Pointer to the CRSFEndpoint that will be added to the endpoint's managed endpoints.
     */
    void addEndpoint(CRSFEndpoint *endpoint);

    /**
     * Processes a CRSF message received by a connector and determines the appropriate actions.
     *
     * This function evaluates the received message to determine whether it should be handled
     * directly, routed to another device, or delivered to one of the connectors managed by
     * the CRSFRouter instance. It ensures proper routing of messages based on their type
     * and destination address, including device-based and broadcast scenarios.
     *
     * @param connector Pointer to the CRSFConnector that received the message.
     * @param message Pointer to the CRSF message header structure containing the message data.
     */
    void processMessage(CRSFConnector *connector, const crsf_header_t *message) const;

    /**
     * Routes a CRSF message received by a connector to its appropriate destination.
     *
     * This function determines whether the message is device-specific or a broadcast message
     * and forwards it accordingly. For device-specific messages with a known destination address,
     * the message is delivered to the connector responsible for that address. For broadcast messages
     * or messages with an unknown destination, the message is forwarded to all other connectors.
     *
     * @param connector Pointer to the CRSFConnector that received the message.
     * @param message Pointer to the CRSF message header structure containing the message data.
     */
    void deliverMessage(const CRSFConnector *connector, const crsf_header_t *message) const;

    /**
     * Routes a CRSF message to a connector that is known to deliver messages to the given device id.
     *
     * The message is delivered to the connector responsible for the provided destination address. For broadcast messages
     * or messages with an unknown destination, the message is forwarded to all other connectors.
     *
     * @param destination The device_id of the target for this message.
     * @param message Pointer to the CRSF message header structure containing the message data.
     */
    void deliverMessageTo(const crsf_addr_e destination, const crsf_header_t *message) const;

    /**
     * Sets the header fields and calculates the CRC for a CRSF frame.
     *
     * This function populates the provided CRSF frame header with the specified frame type,
     * size, and destination address. It then calculates and appends the CRC to the frame.
     *
     * @param frame Pointer to the CRSF frame header structure that will be populated and updated.
     * @param frameType The type of the CRSF frame to be set in the header.
     * @param frameSize The size of the CRSF frame, including payload and header fields (type and CRC).
     */
    void SetHeaderAndCrc(crsf_header_t *frame, crsf_frame_type_e frameType, uint8_t frameSize);

    /**
     * Sets the extended header fields and calculates the CRC for a CRSF frame.
     *
     * This function populates the extended header of a CRSF frame with the specified frame type,
     * size, and destination address. It also sets the originating address using the device ID
     * and calculates the CRC for the frame.
     *
     * @param frame Pointer to the CRSF extended header structure that will be populated and updated.
     * @param frameType The type of the CRSF frame to be set in the extended header.
     * @param frameSize The size of the CRSF frame, including payload, header (type, destination, origin, and CRC fields).
     * @param destAddr The destination address for the CRSF frame, as defined in the CRSF addressing scheme.
     * @param origAddr
     */
    void SetExtendedHeaderAndCrc(crsf_ext_header_t *frame, crsf_frame_type_e frameType, uint8_t frameSize, crsf_addr_e destAddr, crsf_addr_e origAddr);

    /**
     * Constructs a CRSF link statistics packet and populates the provided buffer.
     *
     * @param buffer Pointer to the buffer where the constructed packet will be stored.
     *               It is the caller's responsibility to ensure that the buffer
     *               has sufficient size to hold the generated packet.
     */
    void makeLinkStatisticsPacket(uint8_t *buffer);

    /**
     * Constructs an MSPv2 request frame and initializes it with the provided function and payload.
     *
     * @param frame Pointer to the buffer where the MSPv2 request frame will be constructed.
     * @param function The MSP function code that identifies the type of request being made.
     * @param payload Pointer to the payload data that will be included in the request.
     * @param payloadLength The length of the payload data in bytes.
     */
    void SetMspV2Request(uint8_t *frame, uint16_t function, const uint8_t *payload, uint8_t payloadLength);

    /**
     * Adds an MSP (Multiwii Serial Protocol) message to be processed by the CRSFRouter.
     *
     * This method encapsulates and prepares the MSP message with the provided packet data,
     * destination, and origin, then sends it for further processing within the system. It ensures
     * the message adheres to the required CRSF frame structure and calculates the necessary CRC values.
     *
     * @param packet Pointer to the mspPacket_t structure containing the MSP message payload and its associated metadata.
     * @param destination The target address within the CRSF system to which the message is directed.
     * @param origin The identifier indicating the source of the MSP message within the CRSF system.
     */
    void AddMspMessage(const mspPacket_t *packet, crsf_addr_e destination, crsf_addr_e origin);

    uint8_t getConnectorMaxPacketSize(crsf_addr_e origin) const;

    GENERIC_CRC8 crsf_crc = GENERIC_CRC8(CRSF_CRC_POLY);

private:
    std::set<CRSFConnector *> connectors;
    std::set<CRSFEndpoint *> endpoints;
};

