{
    #ifdef BUILD_VESC_UART

    DBGLN("SerialVESC::begin %u %d", idx, pin);

    this->idx = idx;

    if (pin < 0) {
        // TX pin is configured as main TX output
        pin = GPIO_PIN_RCSIGNAL_TX;
    }
    if (pin < 0) {
        for (uint8_t ch = 0; ch < GPIO_PIN_PWM_OUTPUTS_COUNT; ch++)
