template <int N>
bool getCrossfireTelemetryValue(uint8_t index, int32_t& value,
                                uint8_t* rxBuffer)
{
  bool result = false;
  uint8_t * byte = &rxBuffer[index];
  value = (*byte & 0x80) ? -1 : 0;
  for (uint8_t i=0; i<N; i++) {
    value <<= 8;
    if (*byte != 0xff) {
      result = true;
    }
    value += *byte++;
  }
  return result;
}

