function buildFaviconDataUrl() {
    const svgMarkup = `
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512">
            <path fill="#666" d="${LOGO_PATHS[0]}"/>
            <path fill="#666" d="${LOGO_PATHS[1]}"/>
            <!-- FEATURE:IS_TX -->
            <circle cx="420" cy="420" r="75" fill="#1565c0" stroke="#fff" stroke-width="12"/>
            <!-- /FEATURE:IS_TX -->
            <!-- FEATURE:NOT IS_TX -->
            <circle cx="420" cy="420" r="75" fill="#e53935" stroke="#fff" stroke-width="12"/>
            <!-- /FEATURE:NOT IS_TX -->
            </svg>
        `
    return `data:image/svg+xml,${encodeURIComponent(svgMarkup)}`
}

@customElement('elrs-app')
export class App extends LitElement {
    @query("#sidedrawer") accessor sidedrawerEl
    @query("#main") accessor mainEl

    menu = svg`<svg width="40" height="40" viewBox="0 0 512 512"><path fill="none" stroke="currentColor" stroke-linecap="round" stroke-miterlimit="10" stroke-width="48" d="M88 152h336M88 256h336M88 360h336"/></svg>`

    // Track the currently rendered route so we can restore it when a page blocks navigation
    currentRoute = null

    constructor() {
        super()
        // Bind methods used as callbacks to preserve `this`
        this.renderRoute = this.renderRoute.bind(this)
        this.showSidedrawer = this.showSidedrawer.bind(this)
        this.hideSidedrawer = this.hideSidedrawer.bind(this)
    }

    createRenderRoot() {
        return this
    }

    updateFavicon() {
        const href = buildFaviconDataUrl()
        let link = document.querySelector('link[rel="icon"]')
        if (!link) {
            link = document.createElement('link')
            link.rel = 'icon'
            link.type = 'image/svg+xml'
            document.head.appendChild(link)
        }
        link.href = href
    }

    render() {
        return html`
            <div id="sidedrawer" class="mui--no-user-select">
                <div id="sidedrawer-brand" class="mui--appbar-line-height" style="padding-top: 16px">
                    <svg viewBox="0 0 512 512" width="64px" >
                        <path fill="#666" d="${LOGO_PATHS[0]}"/>
                        <path fill="#666" d="${LOGO_PATHS[1]}"/>
                    </svg>
                    <span class="mui--text-headline" style="padding-bottom: 16px">ExpressLRS&trade;</span>
                </div>
                <div class="mui-divider"></div>
                <ul>
                    <li>
                        <strong>General</strong>
                        <ul>
                            <li><a id="menu-info" href="#info"><span class="mui--align-middle icon--symbols icon--symbols--info"></span>Information</a></li>
                            <li><a id="menu-binding" href="#binding"><span class="mui--align-middle icon--symbols icon--symbols--bind"></span>Binding</a></li>
                            <li><a id="menu-options" href="#options"><span class="mui--align-middle icon--symbols icon--symbols--options"></span>Options</a></li>
                            <!-- FEATURE:IS_TX -->
                            ${elrsState.config['button-actions'] && elrsState.config['button-actions'].length !== 0 ? html`
                                <li><a id="menu-buttons" href="#buttons"><span class="mui--align-middle icon--symbols icon--symbols-buttons"></span>Buttons</a></li>
                            ` : ''}
                            <li><a id="menu-models" href="#models"><span class="mui--align-middle icon--symbols icon--symbols--settings"></span>Import/Export</a></li>
                            <!-- /FEATURE:IS_TX -->
                            <!-- FEATURE:NOT IS_TX -->
                            ${elrsState.config.pwm !== undefined ? html`
                            <li><a id="menu-connections" href="#connections"><span class="mui--align-middle icon--symbols icon--symbols--connections"></span>Connections</a></li>
                            ` : ''}
                            <li><a id="menu-serial" href="#serial"><span class="mui--align-middle icon--symbols icon--symbols--serial"></span>Serial</a></li>
                            <!-- /FEATURE:NOT IS_TX -->
                            <li><a id="menu-wifi" href="#wifi"><span class="mui--align-middle icon--symbols icon--symbols--wifi"></span>WiFi</a></li>
                            <li><a id="menu-update" href="#update"><span class="mui--align-middle icon--symbols icon--symbols--update"></span>Update</a></li>
                        </ul>
                    </li>
                    <li>
                        <strong>Advanced</strong>
                        <ul>
                            <li><a id="menu-hardware" href="#hardware"><span class="mui--align-middle icon--symbols icon--symbols--hardware"></span>Hardware Layout</a></li>
                            <li><a id="menu-cw" href="#cw"><span class="mui--align-middle icon--symbols icon--symbols--wave"></span>Continuous Wave</a></li>
                            <!-- FEATURE:HAS_LR1121 -->
                            <li><a id="menu-lr1121" href="#lr1121"><span class="mui--align-middle icon--symbols icon--symbols--lr1121"></span>LR1121 Firmware</a></li>
                            <!-- /FEATURE:HAS_LR1121 -->
                        </ul>
                    </li>
                </ul>
            </div>
            <header id="header" class="mui-appbar elrs-header">
                <div class="mui--appbar-height" style="align-items: center; display: flex">
                    <div style="padding-left: 16px">
                        <a class="mui--align-middle sidedrawer-toggle mui--visible-xs-inline-block mui--visible-sm-inline-block js-show-sidedrawer"
                           @click="${this.showSidedrawer}">${this.menu}</a>
                        <a class="mui--align-middle sidedrawer-toggle mui--hidden-xs mui--hidden-sm js-hide-sidedrawer"
                           @click="${this.hideSidedrawer}">${this.menu}</a>
                    </div>
                    <div style="padding-left: 15px">
                        <div id="product_name">${elrsState.settings?.product_name}</div>
                        <div>
                            <b>Firmware Rev. </b>${elrsState.settings?.version} ${formatBand()}
                        </div>
                    </div>
                </div>
            </header>
            <div id="content-wrapper">
                <div class="mui--appbar-height"></div>
                <div id="main" class="mui-container-fluid"></div>
            </div>
            <elrs-footer></elrs-footer>
        `
    }

    firstUpdated(_changedProperties) {
        this.updateFavicon()
        window.addEventListener('hashchange', this.renderRoute)

        // Initial load sequence
        this.loadInitialData().catch(() => {
        }).then(() => {
            this.renderRoute()
        })
    }

    async loadInitialData() {
        try {
            const resp = await fetch('/config')
            if (!resp.ok) throw new Error('Failed to load config')
            const data = await resp.json()
            elrsState.settings = data.settings || {}
            elrsState.options = data.options || {}
            elrsState.config = data.config || {}
            document.title = 'ExpressLRS ' + data.settings["module-type"] + ' WebUI'
            this.requestUpdate()
        } catch (e) {
            console.warn('Startup data load failed:', e)
        }
    }

    scrollMainToTop() {
        const doScroll = (behavior = 'smooth') => {
            try {
                window.scrollTo({top: 0, left: 0, behavior})
            } catch {
                window.scrollTo(0, 0)
            }
        }
        requestAnimationFrame(() => requestAnimationFrame(() => doScroll('smooth')))
    }

    setActiveMenu(route) {
        // Sidedrawer may be moved into MUI overlay, making @query return null; resolve robustly
        const sidedrawer = this.sidedrawerEl || this.querySelector('#sidedrawer') || document.getElementById('sidedrawer')
        if (sidedrawer) {
            const links = sidedrawer.querySelectorAll('a[href^="#"]')
            links.forEach(a => a.classList.remove('active'))
        }
        const id = 'menu-' +route
        const el = id ? (this.querySelector(`#${id}`) || document.getElementById(id)) : null
        if (el) el.classList.add('active')
    }

    buildRouteContent(route) {
        switch (route) {
            case 'info':
                return '<info-panel></info-panel>'
            case 'binding':
                return '<binding-panel></binding-panel>'
            case 'options':
                return FEATURES.IS_TX ? '<tx-options-panel></tx-options-panel>' : '<rx-options-panel></rx-options-panel>'
            case 'wifi':
                return '<wifi-panel></wifi-panel>'
            case 'update':
                return '<update-panel></update-panel>'
            case 'connections':
                return !FEATURES.IS_TX && elrsState.config.pwm !== undefined ? '<connections-panel></connections-panel>' : ''
            case 'serial':
                return !FEATURES.IS_TX ? '<serial-panel></serial-panel>' : ''
            case 'buttons':
                return FEATURES.IS_TX ? '<buttons-panel></buttons-panel>' : ''
            case 'hardware':
                return '<hardware-layout></hardware-layout>'
            case 'cw':
                return '<continuous-wave></continuous-wave>'
            case 'models':
                return '<models-panel></models-panel>'
            case 'lr1121':
                return FEATURES.HAS_LR1121 ? '<lr1121-updater></lr1121-updater>' : ''
            default:
                return ''
        }
    }

    generalGroupLoaded = false
    advancedGroupLoaded = false

    async loadGeneralGroup() {
        if (this.generalGroupLoaded) return
        try {
            const imports = [
                import('./pages/binding-panel.js'),
                import('./pages/wifi-panel.js'),
                import('./pages/update-panel.js')
            ]
            // FEATURE:IS_TX
            imports.push(import('./pages/tx-options-panel.js'))
            // FEATURE:NOT IS_8285
            imports.push(import('./pages/models-panel.js'))
            // /FEATURE:NOT IS_8285
            imports.push(import('./pages/buttons-panel.js'))
            // /FEATURE:IS_TX
            // FEATURE:NOT IS_TX
            imports.push(import('./pages/rx-options-panel.js'))
            imports.push(import('./pages/connections-panel.js'))
            imports.push(import('./pages/serial-panel.js'))
            // /FEATURE:NOT IS_TX
            await Promise.all(imports)
        } finally {
            this.generalGroupLoaded = true
        }
    }

    async loadAdvancedGroup() {
        if (this.advancedGroupLoaded) return
        try {
            const imports = [
                import('./pages/hardware-layout.js'),
                import('./pages/continuous-wave.js')
            ]
            // FEATURE:HAS_LR1121
            imports.push(import('./pages/lr1121-updater.js'))
            // /FEATURE:HAS_LR1121
            await Promise.all(imports)
        } finally {
            this.advancedGroupLoaded = true
        }
    }

    async ensureLoadedForRoute(route) {
        const generalRoutes = ['binding', 'options', 'wifi', 'update', 'connections', 'serial', 'buttons', 'models']
        const advancedRoutes = ['hardware', 'cw', 'lr1121']
        if (generalRoutes.includes(route)) {
            await this.loadGeneralGroup()
        } else if (advancedRoutes.includes(route)) {
            await this.loadAdvancedGroup()
        }
    }

    replaceMainWithTransition(newContent) {
        return new Promise(resolve => {
            const onEnd = () => {
                this.mainEl.removeEventListener('transitionend', onEnd)
                if (typeof newContent === 'string') {
                    this.mainEl.innerHTML = newContent
                } else if (newContent instanceof Node) {
                    this.mainEl.innerHTML = ''
                    this.mainEl.appendChild(newContent)
                } else {
                    this.mainEl.innerHTML = ''
                }
                this.mainEl.classList.add('route-fade-in')
                requestAnimationFrame(() => {
                    this.mainEl.classList.remove('route-fade-out')
                    requestAnimationFrame(() => {
                        this.mainEl.classList.remove('route-fade-in')
                        resolve()
                    })
                })
            }
            this.mainEl.addEventListener('transitionend', onEnd)
            this.mainEl.classList.add('route-fade-out')
            setTimeout(onEnd, 220)
        })
    }

    async renderRoute() {
        const route = (location.hash || '#info').replace('#', '')

        // If we are already on this route, do nothing
        if (this.currentRoute && route === this.currentRoute) {
            this.setActiveMenu(route)
            return
        }

        // Navigation guard: ask the current page component if we can leave
        const currentEl = this.mainEl?.firstElementChild
        if (currentEl && typeof currentEl.checkChanged === 'function') {
            try {
                let hasChanges = currentEl.checkChanged()
                let navigate = true;
                if (hasChanges === true) {
                   navigate = (await cuteAlert({type: 'question', message: 'Do you wish to navigate away and discard changes to this page?', title: 'Configuration Changed', confirmText: 'Discard', cancelText: 'Cancel'})) === 'confirm'
                }
                if (navigate === false) {
                    // Revert the hash to the previous route and exit
                    if (this.currentRoute && this.currentRoute !== route) {
                        if (('#' + this.currentRoute) !== location.hash) {
                            location.hash = '#' + this.currentRoute
                        }
                        this.setActiveMenu(this.currentRoute)
                    }
                    return
                }
            } catch {
                // If the hook throws, proceed with navigation
            }
        }

        await this.ensureLoadedForRoute(route)
        this.setActiveMenu(route)
        try {
            mui.overlay('off')
        } catch {
        }
        document.body.classList.remove('hide-sidedrawer')
        const sd = this.querySelector('#sidedrawer') || document.getElementById('sidedrawer')
        if (sd) sd.classList.remove('active')
        const content = this.buildRouteContent(route)
        await this.replaceMainWithTransition(content)
        this.scrollMainToTop()
        this.currentRoute = route
    }

    showSidedrawer() {
        const sidedrawer = this.sidedrawerEl
        if (!sidedrawer) return
        const options = {
            onclose: () => {
                sidedrawer.classList.remove('active')
                // Append back into the component so @query can find it again
                this.appendChild(sidedrawer)
            }
        }
        const overlayEl = mui.overlay('on', options)
        overlayEl.appendChild(sidedrawer)
        setTimeout(() => sidedrawer.classList.add('active'), 20)
    }

    hideSidedrawer() {
        document.body.classList.toggle('hide-sidedrawer')
    }
}

